const assert = require("node:assert/strict");
const fs = require("node:fs");
const path = require("node:path");
const test = require("node:test");
const vm = require("node:vm");

const INDEX_PATH = path.join(__dirname, "..", "index.html");
const STORAGE_KEY = "pocketledger.expenses.v1";

test("category filtering narrows expenses and monthly category totals use the current month", () => {
  const expenses = [
    {
      id: "grocery-july",
      cents: 1250,
      category: "Groceries",
      date: "2026-07-03",
      note: "Market",
      createdAt: "2026-07-03T10:00:00.000Z"
    },
    {
      id: "transport-july",
      cents: 320,
      category: "Transport",
      date: "2026-07-04",
      note: "Bus",
      createdAt: "2026-07-04T10:00:00.000Z"
    },
    {
      id: "grocery-june",
      cents: 999,
      category: "Groceries",
      date: "2026-06-28",
      note: "Last month",
      createdAt: "2026-06-28T10:00:00.000Z"
    }
  ];

  const app = loadPocketLedger({
    [STORAGE_KEY]: JSON.stringify(expenses)
  });

  const categoryFilter = app.document.getElementById("categoryFilter");
  assert.ok(categoryFilter, "expected a category filter control");

  categoryFilter.value = "Transport";
  categoryFilter.dispatchEvent({ type: "change" });

  assert.equal(app.document.getElementById("countLabel").textContent, "1 item");
  assert.match(textOf(app.document.getElementById("expenseList")), /Transport/);
  assert.doesNotMatch(textOf(app.document.getElementById("expenseList")), /Groceries/);

  const totalsText = textOf(app.document.getElementById("categoryTotals"));
  assert.match(totalsText, /Groceries/);
  assert.match(totalsText, /\u20ac12\.50|EUR\s*12\.50/);
  assert.match(totalsText, /Transport/);
  assert.match(totalsText, /\u20ac3\.20|EUR\s*3\.20/);
  assert.doesNotMatch(totalsText, /22\.49/, "previous-month groceries should not be included");
});

test("CSV export downloads every stored expense even when the list is filtered", () => {
  const expenses = [
    {
      id: "grocery-july",
      cents: 1234,
      category: "Groceries, weekly",
      date: "2026-07-03",
      note: 'Fruit "box"',
      createdAt: "2026-07-03T10:00:00.000Z"
    },
    {
      id: "transport-july",
      cents: 320,
      category: "Transport",
      date: "2026-07-04",
      note: "Bus",
      createdAt: "2026-07-04T10:00:00.000Z"
    }
  ];

  const app = loadPocketLedger({
    [STORAGE_KEY]: JSON.stringify(expenses)
  });

  const categoryFilter = app.document.getElementById("categoryFilter");
  categoryFilter.value = "Transport";
  categoryFilter.dispatchEvent({ type: "change" });

  const exportButton = app.document.getElementById("exportCsv");
  assert.ok(exportButton, "expected an export CSV button");

  exportButton.dispatchEvent({ type: "click" });

  assert.equal(app.downloads.anchors.length, 1, "expected one download click");
  assert.equal(app.downloads.anchors[0].download, "pocketledger-expenses.csv");
  assert.equal(app.downloads.blobs.length, 1, "expected one CSV blob");
  assert.equal(app.downloads.blobs[0].type, "text/csv;charset=utf-8");
  assert.equal(app.downloads.blobs[0].parts.join(""), [
    "date,category,amount_eur,note,created_at",
    "2026-07-04,Transport,3.20,Bus,2026-07-04T10:00:00.000Z",
    '2026-07-03,"Groceries, weekly",12.34,"Fruit ""box""",2026-07-03T10:00:00.000Z',
    ""
  ].join("\r\n"));
});
function loadPocketLedger(initialStorage) {
  const html = fs.readFileSync(INDEX_PATH, "utf8");
  const script = html.match(/<script>\s*([\s\S]*?)\s*<\/script>/i)[1];
  const downloads = {
    anchors: [],
    blobs: [],
    revoked: []
  };
  const document = createDocument(html, downloads);
  const localStorage = createLocalStorage(initialStorage);
  const window = {
    Blob: class Blob {
      constructor(parts, options) {
        this.parts = parts;
        this.type = options && options.type || "";
      }
    },
    crypto: {
      randomUUID: () => "fixed-id"
    },
    URL: {
      createObjectURL(blob) {
        downloads.blobs.push(blob);
        return "blob:pocketledger-csv";
      },
      revokeObjectURL(url) {
        downloads.revoked.push(url);
      }
    }
  };

  window.window = window;
  window.document = document;
  window.localStorage = localStorage;
  window.Intl = Intl;
  window.Number = Number;
  window.String = String;
  window.Array = Array;
  window.JSON = JSON;
  window.Math = Math;
  window.RegExp = RegExp;
  window.Date = fixedDate("2026-07-08T12:00:00.000Z");
  document.defaultView = window;

  vm.runInNewContext(script, window, {
    filename: "index.html"
  });

  return { document, downloads, localStorage, window };
}

function createDocument(html, downloads) {
  const elements = new Map();
  const document = {
    body: new Element("body"),
    defaultView: null,
    createElement(tagName) {
      const element = new Element(tagName);
      if (String(tagName).toLowerCase() === "a") {
        element.click = function () {
          downloads.anchors.push(this);
        };
      }
      return element;
    },
    getElementById(id) {
      return elements.get(id) || null;
    }
  };

  for (const match of html.matchAll(/<([a-zA-Z0-9-]+)[^>]*\bid="([^"]+)"/g)) {
    const element = new Element(match[1]);
    element.id = match[2];
    elements.set(element.id, element);
  }

  return document;
}

function createLocalStorage(initialStorage) {
  const values = new Map(Object.entries(initialStorage || {}));
  return {
    getItem(key) {
      return values.has(key) ? values.get(key) : null;
    },
    setItem(key, value) {
      values.set(key, String(value));
    }
  };
}

function fixedDate(isoNow) {
  const RealDate = Date;

  function FixedDate() {
    if (!(this instanceof FixedDate)) {
      return RealDate.apply(null, arguments);
    }

    if (arguments.length === 0) {
      return new RealDate(isoNow);
    }

    return new RealDate(...arguments);
  }

  FixedDate.now = () => new RealDate(isoNow).getTime();
  FixedDate.UTC = RealDate.UTC;
  FixedDate.parse = RealDate.parse;
  FixedDate.prototype = RealDate.prototype;
  return FixedDate;
}

class Element {
  constructor(tagName) {
    this.tagName = String(tagName).toUpperCase();
    this.attributes = new Map();
    this.children = [];
    this.eventListeners = new Map();
    this.parentNode = null;
    this.className = "";
    this.dateTime = "";
    this.disabled = false;
    this.download = "";
    this.hidden = false;
    this.href = "";
    this.id = "";
    this.innerHTML = "";
    this.required = false;
    this.textContent = "";
    this.type = "";
    this.value = "";
  }

  addEventListener(type, listener) {
    const listeners = this.eventListeners.get(type) || [];
    listeners.push(listener);
    this.eventListeners.set(type, listeners);
  }

  append() {
    for (const child of arguments) {
      this.appendChild(child);
    }
  }

  appendChild(child) {
    if (typeof child === "string") {
      child = new TextNode(child);
    }

    child.parentNode = this;
    this.children.push(child);
    return child;
  }

  removeChild(child) {
    this.children = this.children.filter((existing) => existing !== child);
    child.parentNode = null;
    return child;
  }

  closest(selector) {
    if (selector !== "[data-delete-id]") {
      return null;
    }

    let node = this;
    while (node) {
      if (node.attributes && node.attributes.has("data-delete-id")) {
        return node;
      }
      node = node.parentNode;
    }
    return null;
  }

  dispatchEvent(event) {
    event.target = event.target || this;
    event.currentTarget = this;
    event.preventDefault = event.preventDefault || function () {};

    for (const listener of this.eventListeners.get(event.type) || []) {
      listener.call(this, event);
    }
  }

  focus() {}

  getAttribute(name) {
    return this.attributes.get(name) || null;
  }

  reportValidity() {}

  replaceChildren() {
    this.children = [];
    this.textContent = "";

    for (const child of arguments) {
      this.appendChild(child);
    }
  }

  reset() {
    this.value = "";
  }

  setAttribute(name, value) {
    this.attributes.set(name, String(value));
  }

  setCustomValidity() {}
}

class TextNode {
  constructor(text) {
    this.textContent = text;
    this.children = [];
  }
}

function textOf(node) {
  if (!node) {
    return "";
  }

  return [node.textContent]
    .concat(node.children.map(textOf))
    .join(" ");
}
